module top_module(
    input [2:0] select,
    input [7:0] data_in,
    output reg output_data
);always @* begin
    case (select)
      3'b000: output_data = data_in[0];
      3'b001: output_data = data_in[1];
      3'b010: output_data = data_in[2];
      3'b011: output_data = data_in[3];
      3'b100: output_data = data_in[4];
      3'b101: output_data = data_in[5];
      3'b110: output_data = data_in[6];
      3'b111: output_data = data_in[7];
    endcase
  end
endmodule
